import{_ as a,o as i,c as n,ae as t}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"iOS 17 Privacy Changes","description":"","frontmatter":{"title":"iOS 17 Privacy Changes","slug":"ios-17-privacy-changes"},"headers":[],"relativePath":"account-hub/ios-17-privacy-changes.md","filePath":"account-hub/ios-17-privacy-changes.md"}'),r={name:"account-hub/ios-17-privacy-changes.md"};function s(o,e,c,d,l,p){return i(),n("div",null,[...e[0]||(e[0]=[t('<p>This year, Apple announced the upcoming release of iOS 17 and gave the industry insight into the privacy regulations packaged into that release. In response, Branch is proactively implementing updates to our platform to align with the new privacy regulations.</p><h3 id="privacy-manifest-file-creation" tabindex="-1">Privacy Manifest File Creation <a class="header-anchor" href="#privacy-manifest-file-creation" aria-label="Permalink to &quot;Privacy Manifest File Creation&quot;">​</a></h3><p>Branch now supports Privacy Manifest files, an essential addition for App Store submissions.</p><p>Branch&#39;s own iOS SDK Privacy Manifest <a href="https://github.com/BranchMetrics/ios-branch-deep-linking-attribution/blob/master/Framework/PrivacyInfo.xcprivacy" target="_blank" rel="noreferrer">file</a> includes:</p><ul><li>The declaration of <code>NSPrivacyTrackingDomains</code> to meet Apple&#39;s requirements.</li><li>A list of <code>NSPrivacyAccessedAPITypes</code> with valid use reasons.</li><li>Details on the data that the Branch iOS SDK collects, referred to as <code>NSPrivacyCollectedDataTypes</code>.</li></ul><p><strong>Note</strong>: If you are collecting and passing info to the Branch iOS SDK, you need to declare that in your own Privacy Manifest file in your app, since Branch cannot see the data being passed. This includes things like hashed identifiers and other sensitive information.</p><h3 id="sdk-and-backend-updates" tabindex="-1">SDK and Backend Updates <a class="header-anchor" href="#sdk-and-backend-updates" aria-label="Permalink to &quot;SDK and Backend Updates&quot;">​</a></h3><p>Branch has updated the iOS SDK as well as our backend to adhere to iOS 17 privacy policies.</p><p>Updates include:</p><ul><li><p>Changes to support compliance and flexibility for tracking and measurement.</p></li><li><p>The creation of dedicated domains for network requests:</p><ul><li>A dedicated tracking domain (api-safetrack.branch.io), designed for ads measurement, is declared in the privacy manifest. Branch will only use this domain when users have opted in to App Tracking Transparency (ATT).</li><li>A dedicated non-tracking domain (api3.branch.io) used by Branch for API requests related to non-ads measurement and deep linking. Notably, there’s no requirement to declare this domain in the privacy manifest, since traffic through it doesn’t contribute to “tracking” (ads measurement).</li></ul></li></ul><h3 id="sdk-signing" tabindex="-1">SDK Signing <a class="header-anchor" href="#sdk-signing" aria-label="Permalink to &quot;SDK Signing&quot;">​</a></h3><p>Starting with iOS 17, Branch will sign the iOS SDK to support user privacy. This aligns with Apple&#39;s requirements for Spring 2024 compliance.</p>',12)])])}const f=a(r,[["render",s]]);export{u as __pageData,f as default};
